def calculate_binary_info(self):
    """
    Calcola le informazioni sulla stringa binaria, inclusa la percentuale di 0 e 1, e la lunghezza totale della stringa binaria.
    >>> bdp = BinaryDataProcessor("0110100001100101011011000110110001101111")
    >>> bdp.calculate_binary_info()
    {'Zeroes': 0.475, 'Ones': 0.525, 'Bit length': 40}

    """
    binary_string = self.binary_string
    total_length = len(binary_string)

    if total_length == 0:
        return {'Zeroes': 0.0, 'Ones': 0.0, 'Bit length': 0}

    count_zeroes = binary_string.count('0')
    count_ones = binary_string.count('1')

    percentage_zeroes = count_zeroes / total_length
    percentage_ones = count_ones / total_length

    return {
        'Zeroes': percentage_zeroes,
        'Ones': percentage_ones,
        'Bit length': total_length
    }

def check_winner(self, player_hand, dealer_hand):
    """
    Determina il vincitore di un gioco confrontando i valori delle mani del giocatore e del dealer.
    regola:
    Se entrambi i giocatori hanno valori delle mani che sono uguali o inferiori a 21, il vincitore è colui il cui valore della mano è più vicino a 21.
    Altrimenti, il vincitore è colui che ha il valore della mano più basso.
    :param player_hand: lista
    :param dealer_hand: lista
    :return: il risultato del gioco, solo due stringhe certe: 'Il dealer vince' o 'Il giocatore vince'
    >>> black_jack_game.check_winner(['QD', '9D', 'JC', 'QH', 'AS'], ['QD', '9D', 'JC', 'QH', '2S'])
    'Il giocatore vince'
    """
    def calculate_hand_value(hand):
        value = 0
        aces = 0

        for card in hand:
            rank = card[:-1]  # Rimuove il seme (ultimo carattere)

            if rank in ['J', 'Q', 'K']:
                value += 10
            elif rank == 'A':
                aces += 1
                value += 11
            else:
                value += int(rank)

        # Aggiusta il valore degli assi se necessario
        while value > 21 and aces > 0:
            value -= 10
            aces -= 1

        return value

    player_value = calculate_hand_value(player_hand)
    dealer_value = calculate_hand_value(dealer_hand)

    # Se entrambi <= 21, vince chi è più vicino a 21
    if player_value <= 21 and dealer_value <= 21:
        if player_value >= dealer_value:
            return 'Il giocatore vince'
        else:
            return 'Il dealer vince'
    # Altrimenti, vince chi ha il valore più basso
    else:
        if player_value <= dealer_value:
            return 'Il giocatore vince'
        else:
            return 'Il dealer vince'

def remove_book(self, title, quantity):
    """
    Rimuovi uno o più libri dall'inventario che è ordinato per titolo del libro.
    Solleva un'eccezione in caso di input non valido.
    :param title: str, il titolo del libro
    :param quantity: int
    """
    if not isinstance(title, str):
        raise TypeError("Il titolo deve essere una stringa")

    if not isinstance(quantity, int):
        raise TypeError("La quantità deve essere un intero")

    if quantity <= 0:
        raise ValueError("La quantità deve essere maggiore di zero")

    if not title.strip():
        raise ValueError("Il titolo non può essere vuoto")

    # Cerca il libro nell'inventario
    found = False
    for book in self.inventory:
        if book['title'] == title:
            found = True
            if book['quantity'] < quantity:
                raise ValueError(f"Quantità insufficiente. Disponibili: {book['quantity']}, richiesti: {quantity}")

            book['quantity'] -= quantity

            # Se la quantità diventa 0, rimuovi il libro dall'inventario
            if book['quantity'] == 0:
                self.inventory.remove(book)

            break

    if not found:
        raise ValueError(f"Libro '{title}' non trovato nell'inventario")

