def add_table(self, data):
    """
    Aggiunge una tabella al documento Word con i dati specificati.
    :param data: lista di liste, i dati per popolare la tabella.
    :return: bool, True se la tabella è stata aggiunta con successo, False altrimenti.
    """
    try:
        if not data or not isinstance(data, list):
            return False

        # Verifica che tutti gli elementi siano liste
        if not all(isinstance(row, list) for row in data):
            return False

        # Verifica che ci siano righe e colonne
        if len(data) == 0:
            return False

        num_rows = len(data)
        num_cols = len(data[0]) if data else 0

        if num_cols == 0:
            return False

        # Crea la tabella nel documento (assumendo che self.document sia un oggetto python-docx)
        table = self.document.add_table(rows=num_rows, cols=num_cols)

        # Popola la tabella con i dati
        for i, row_data in enumerate(data):
            row_cells = table.rows[i].cells
            for j, cell_value in enumerate(row_data):
                if j < num_cols:
                    row_cells[j].text = str(cell_value)

        return True

    except Exception as e:
        return False

def _get_alignment_value(self, alignment):
    """
    Restituisce il valore di allineamento corrispondente alla stringa di allineamento fornita.
    :param alignment: str, la stringa di allineamento ('sinistra', 'centro' o 'destra').
    :return: int, il valore di allineamento.
    """
    alignment_map = {
        'sinistra': 0,
        'centro': 1,
        'destra': 2
    }
    return alignment_map.get(alignment.lower(), 0)

def find_blank(self, state):
    """
    Trova la posizione vuota dello stato attuale, che è l'elemento 0.
    :param state: una lista di interi di dimensione 3*3, che memorizza lo stato attuale.
    :return i, j: due interi, che rappresentano le coordinate del blocco vuoto.
    >>> eightPuzzle = EightPuzzle([[2, 3, 4], [5, 8, 1], [6, 0, 7]])
    >>> eightPuzzle.find_blank([[2, 3, 4], [5, 8, 1], [6, 0, 7]])
    (2, 1)
    """
    for i in range(len(state)):
        for j in range(len(state[i])):
            if state[i][j] == 0:
                return (i, j)

def calculate(self, expression):
    """
    Calcola il risultato dell'espressione postfix fornita
    :param expression: stringa, l'espressione postfix da calcolare
    :return: float, il risultato calcolato
    >>> expression_calculator = ExpressionCalculator()
    >>> expression_calculator.calculate("2 + 3 * 4")
    14.0

    """
    # Convert infix to postfix first, then evaluate
    def precedence(op):
        if op in ['+', '-']:
            return 1
        if op in ['*', '/']:
            return 2
        return 0

    def infix_to_postfix(expr):
        output = []
        stack = []
        tokens = expr.replace('(', ' ( ').replace(')', ' ) ').split()

        for token in tokens:
            if token.replace('.', '').replace('-', '').isdigit():
                output.append(token)
            elif token == '(':
                stack.append(token)
            elif token == ')':
                while stack and stack[-1] != '(':
                    output.append(stack.pop())
                if stack:
                    stack.pop()
            elif token in ['+', '-', '*', '/']:
                while stack and stack[-1] != '(' and precedence(stack[-1]) >= precedence(token):
                    output.append(stack.pop())
                stack.append(token)

        while stack:
            output.append(stack.pop())

        return output

    def evaluate_postfix(postfix):
        stack = []
        for token in postfix:
            if token in ['+', '-', '*', '/']:
                b = stack.pop()
                a = stack.pop()
                if token == '+':
                    stack.append(a + b)
                elif token == '-':
                    stack.append(a - b)
                elif token == '*':
                    stack.append(a * b)
                elif token == '/':
                    stack.append(a / b)
            else:
                stack.append(float(token))

        return stack[0]

    postfix = infix_to_postfix(expression)
    return evaluate_postfix(postfix)

