def is_valid(self):
    """
    Giudica se l'indirizzo IP è valido, cioè se l'indirizzo IP è composto da quattro cifre decimali separate da '.'. Ogni cifra è maggiore o uguale a 0 e minore o uguale a 255.
    :return: bool
    >>> ipaddress = IPAddress("10.10.10.10")
    >>> ipaddress.is_valid()
    True
    """
    if not hasattr(self, 'ip') and not hasattr(self, 'address'):
        return False

    ip_str = self.ip if hasattr(self, 'ip') else self.address

    if not isinstance(ip_str, str):
        return False

    parts = ip_str.split('.')

    if len(parts) != 4:
        return False

    for part in parts:
        if not part:
            return False

        if not part.isdigit():
            return False

        if part[0] == '0' and len(part) > 1:
            return False

        num = int(part)
        if num < 0 or num > 255:
            return False

    return True

def is_valid_ipv4(ip_address):
    """
    Controlla se l'indirizzo IP fornito è un indirizzo IPv4 valido.
    :param ip_address: stringa, l'indirizzo IP da controllare
    :return: bool, True se l'indirizzo IP è valido, False altrimenti
    >>> IpUtil.is_valid_ipv4('192.168.0.123')
    True
    >>> IpUtil.is_valid_ipv4('256.0.0.0')
    False

    """
    if not isinstance(ip_address, str):
        return False

    parts = ip_address.split('.')

    if len(parts) != 4:
        return False

    for part in parts:
        if not part:
            return False

        if not part.isdigit():
            return False

        if part[0] == '0' and len(part) > 1:
            return False

        num = int(part)
        if num < 0 or num > 255:
            return False

    return True

def is_valid_move(self, pos1, pos2):
    """
    verifica se il movimento di due icone è valido (cioè le posizioni sono all'interno dell'intervallo della tavola da gioco, le due posizioni non sono le stesse, le due posizioni hanno la stessa icona e c'è un percorso valido tra le due posizioni)
    :param pos1: tupla di posizione (x, y) della prima icona
    :param pos2: tupla di posizione (x, y) della seconda icona
    :return: True o False, che rappresenta se il movimento di due icone è valido
    """
    # Verifica che le posizioni siano all'interno della tavola
    if not (0 <= pos1[0] < len(self.board[0]) and 0 <= pos1[1] < len(self.board)):
        return False
    if not (0 <= pos2[0] < len(self.board[0]) and 0 <= pos2[1] < len(self.board)):
        return False

    # Verifica che le due posizioni non siano le stesse
    if pos1 == pos2:
        return False

    # Verifica che le due posizioni abbiano la stessa icona
    if self.board[pos1[1]][pos1[0]] != self.board[pos2[1]][pos2[0]]:
        return False

    # Verifica che ci sia un percorso valido tra le due posizioni
    # Nel Mahjong Connect, un percorso valido può avere al massimo 2 svolte (3 segmenti di linea)
    return self.has_valid_path(pos1, pos2)


def has_valid_path(self, pos1, pos2):
    """
    Verifica se esiste un percorso valido tra due posizioni con al massimo 2 svolte
    """
    # Percorso diretto (0 svolte)
    if self.is_direct_path(pos1, pos2):
        return True

    # Percorso con 1 svolta
    # Prova il punto intermedio (pos1[0], pos2[1])
    mid1 = (pos1[0], pos2[1])
    if self.is_empty_or_target(mid1, pos1, pos2):
        if self.is_direct_path(pos1, mid1) and self.is_direct_path(mid1, pos2):
            return True

    # Prova il punto intermedio (pos2[0], pos1[1])
    mid2 = (pos2[0], pos1[1])
    if self.is_empty_or_target(mid2, pos1, pos2):
        if self.is_direct_path(pos1, mid2) and self.is_direct_path(mid2, pos2):
            return True

    # Percorso con 2 svolte - esplora tutte le possibili posizioni intermedie
    for y in range(-1, len(self.board) + 1):
        for x in range(-1, len(self.board[0]) + 1):
            mid = (x, y)
            if self.is_empty_or_target(mid, pos1, pos2):
                # Controlla percorso pos1 -> mid -> pos2 con 1 svolta in ciascun segmento
                if self.has_one_turn_path(pos1, mid) and self.has_one_turn_path(mid, pos2):
                    return True

    return False


def is_direct_path(self, pos1, pos2):
    """Verifica se c'è un percorso diretto (orizzontale o verticale) senza ostacoli"""
    if pos1[0] == pos2[0]:  # Stesso x, percorso verticale
        y_min, y_max = min(pos1[1], pos2[1]), max(pos1[1], pos2[1])
        for y in range(y_min + 1, y_max):
            if not self.is_empty_or_target((pos1[0], y), pos1, pos2):
                return False
        return True
    elif pos1[1] == pos2[1]:  # Stesso y, percorso orizzontale
        x_min, x_max = min(pos1[0], pos2[0]), max(pos1[0], pos2[0])
        for x in range(x_min + 1, x_max):
            if not self.is_empty_or_target((x, pos1[1]), pos1, pos2):
                return False
        return True
    return False


def has_one_turn_path(self, pos1, pos2):
    """Verifica se c'è un percorso con esattamente 1 svolta"""
    mid1 = (pos1[0], pos2[1])
    if self.is_empty_or_target(mid1, pos1, pos2):
        if self.is_direct_path(pos1, mid1) and self.is_direct_path(mid1, pos2):
            return True

    mid2 = (pos2[0], pos1[1])
    if self.is_empty_or_target(mid2, pos1, pos2):
        if self.is_direct_path(pos1, mid2) and self.is_direct_path(mid2, pos2):
            return True

    return False


def is_empty_or_target(self, pos, pos1, pos2):
    """Verifica se una posizione è vuota o è una delle posizioni target"""
    if pos == pos1 or pos == pos2:
        return True
    # Posizioni fuori dalla tavola sono considerate vuote
    if pos[0] < 0 or pos[0] >= len(self.board[0]) or pos[1] < 0 or pos[1] >= len(self.board):
        return True
    return self.board[pos[1]][pos[0]] is None or self.board[pos[1]][pos[0]] == ''

def update(self, predicted_labels, true_labels):
    """
    Aggiorna il numero di tutti e quattro i campioni (veri_positivi, falsi_positivi, falsi_negativi, veri_negativi)
    :param predicted_labels: lista, risultati previsti
    :param true_labels: lista, etichette vere
    :return: None, modifica il numero dei campioni corrispondenti
    >>> mc = MetricsCalculator()
    >>> mc.update([1, 1, 0, 0], [1, 0, 0, 1])
    (self.true_positives, self.false_positives, self.false_negatives, self.true_negatives) = (1, 1, 1, 1)
    """
    for predicted, true in zip(predicted_labels, true_labels):
        if predicted == 1 and true == 1:
            self.true_positives += 1
        elif predicted == 1 and true == 0:
            self.false_positives += 1
        elif predicted == 0 and true == 1:
            self.false_negatives += 1
        elif predicted == 0 and true == 0:
            self.true_negatives += 1

def sweep(self, x, y):
    """
    Scopre la posizione data.
    :param x: La coordinata x della posizione, int.
    :param y: La coordinata y della posizione, int.
    :return: True se il giocatore ha vinto il gioco, False altrimenti; se il gioco continua, restituisce la mappa del giocatore, list.
    >>> minesweeper_game = MinesweeperGame(3, 1)
    >>> minesweeper_game.minesweeper_map = [['X', 1, 0], [1, 1, 0], [0, 0, 0]]
    >>> minesweeper_game.player_map = [['-', '-', '-'], ['-', '-', '-'], ['-', '-', '-']]
    >>> minesweeper_game.sweep(1, 1)
    [['-', '-', '-'], ['-', 1, '-'], ['-', '-', '-']]

    """
    # Se la posizione contiene una mina, il giocatore perde
    if self.minesweeper_map[x][y] == 'X':
        return False

    # Scopre la posizione
    self.player_map[x][y] = self.minesweeper_map[x][y]

    # Se la posizione è 0, scopre ricorsivamente le posizioni adiacenti
    if self.minesweeper_map[x][y] == 0:
        for dx in [-1, 0, 1]:
            for dy in [-1, 0, 1]:
                if dx == 0 and dy == 0:
                    continue
                nx, ny = x + dx, y + dy
                if 0 <= nx < len(self.minesweeper_map) and 0 <= ny < len(self.minesweeper_map[0]):
                    if self.player_map[nx][ny] == '-':
                        self.sweep(nx, ny)

    # Controlla se il giocatore ha vinto
    for i in range(len(self.player_map)):
        for j in range(len(self.player_map[0])):
            if self.player_map[i][j] == '-' and self.minesweeper_map[i][j] != 'X':
                return self.player_map

    return True

def switch_song(self):
    """
    Passa alla canzone successiva nella playlist.
    :return: True se la canzone successiva è stata cambiata, False se non c'era una canzone successiva.
    >>> musicPlayer = MusicPlayer()
    >>> musicPlayer.playlist = ["canzone1", "canzone2"]
    >>> musicPlayer.current_song = "canzone1"
    >>> musicPlayer.switch_song()
    True

    """
    if not self.playlist:
        return False

    if self.current_song is None:
        return False

    try:
        current_index = self.playlist.index(self.current_song)
        if current_index < len(self.playlist) - 1:
            self.current_song = self.playlist[current_index + 1]
            return True
        else:
            return False
    except ValueError:
        return False

@staticmethod
def binary_to_decimal(binary_num):
    """
    Converti un numero dal formato binario al formato decimale.
    :param binary_num: str, numero binario
    :return: int, la rappresentazione decimale del numero binario str.
    >>> NumberConverter.binary_to_decimal('1010010110110111')
    42423
    """
    return int(binary_num, 2)

@staticmethod
def octal_to_decimal(octal_num):
    """
    Converti un numero dal formato ottale al formato decimale.
    :param octal_num: str, numero ottale
    :return: int, la rappresentazione decimale del numero ottale str.
    >>> NumberConverter.octal_to_decimal('122667')
    42423
    """
    return int(octal_num, 8)

@staticmethod
def hex_to_decimal(hex_num):
    """
    Converti un numero dal formato esadecimale al formato decimale.
    :param hex_num: str, numero esadecimale
    :return: int, la rappresentazione decimale della stringa del numero esadecimale.
    >>> NumberConverter.hex_to_decimal('a5b7')
    42423
    """
    return int(hex_num, 16)

def format(self, x):
    """
    Converte un numero nella sua rappresentazione in parole.
    :param x: int o float, il numero da convertire in formato parole
    :return: str, il numero in formato parole
    >>> formatter = NumberWordFormatter()
    >>> formatter.format(123456)
    "CENTO VENTITRE MILA QUATTROCENTO CINQUANTA SEI SOLO"
    """
    if isinstance(x, float):
        int_part = int(x)
        decimal_part = round((x - int_part) * 100)
        if decimal_part == 0:
            return self.format(int_part) + " SOLO"
        else:
            return self.format(int_part) + " VIRGOLA " + self.format(decimal_part)

    if x == 0:
        return "ZERO"

    units = ["", "UNO", "DUE", "TRE", "QUATTRO", "CINQUE", "SEI", "SETTE", "OTTO", "NOVE"]
    teens = ["DIECI", "UNDICI", "DODICI", "TREDICI", "QUATTORDICI", "QUINDICI", "SEDICI", "DICIASSETTE", "DICIOTTO", "DICIANNOVE"]
    tens = ["", "", "VENTI", "TRENTA", "QUARANTA", "CINQUANTA", "SESSANTA", "SETTANTA", "OTTANTA", "NOVANTA"]

    def convert_below_thousand(n):
        if n == 0:
            return ""
        elif n < 10:
            return units[n]
        elif n < 20:
            return teens[n - 10]
        elif n < 100:
            ten = n // 10
            unit = n % 10
            if unit in [1, 8]:
                return tens[ten][:-1] + units[unit]
            else:
                return tens[ten] + units[unit]
        else:
            hundred = n // 100
            remainder = n % 100
            if hundred == 1:
                result = "CENTO"
            else:
                result = units[hundred] + "CENTO"

            if remainder > 0:
                result += " " + convert_below_thousand(remainder)

            return result

    if x < 1000:
        return convert_below_thousand(x) + " SOLO"
    elif x < 1000000:
        thousands = x // 1000
        remainder = x % 1000

        if thousands == 1:
            result = "MILLE"
        else:
            result = convert_below_thousand(thousands) + " MILA"

        if remainder > 0:
            result += " " + convert_below_thousand(remainder)

        return result + " SOLO"
    else:
        millions = x // 1000000
        remainder = x % 1000000

        if millions == 1:
            result = "UN MILIONE"
        else:
            result = convert_below_thousand(millions) + " MILIONI"

        if remainder >= 1000:
            thousands = remainder // 1000
            if thousands == 1:
                result += " MILLE"
            else:
                result += " " + convert_below_thousand(thousands) + " MILA"
            remainder = remainder % 1000

        if remainder > 0:
            result += " " + convert_below_thousand(remainder)

        return result + " SOLO"

def replace(self, string):
    """
    Sostituisce i riferimenti ai caratteri numerici (entità HTML) nella stringa di input con i loro corrispondenti caratteri Unicode.
    :param string: str, la stringa di input contenente riferimenti ai caratteri numerici.
    :return: str, la stringa di input con i riferimenti ai caratteri numerici sostituiti con i loro corrispondenti caratteri Unicode.
    >>> unescaper = NumericEntityUnescaper()
    >>> unescaper.replace("&#65;&#66;&#67;")
    'ABC'

    """
    import re

    def replace_entity(match):
        entity = match.group(0)
        # Remove &#, &#x, or &# prefix and ; suffix
        if entity.startswith('&#x') or entity.startswith('&#X'):
            # Hexadecimal entity
            num_str = entity[3:-1]
            try:
                char_code = int(num_str, 16)
                return chr(char_code)
            except (ValueError, OverflowError):
                return entity
        elif entity.startswith('&#'):
            # Decimal entity
            num_str = entity[2:-1]
            try:
                char_code = int(num_str, 10)
                return chr(char_code)
            except (ValueError, OverflowError):
                return entity
        return entity

    # Pattern to match numeric character references
    # Matches &#digits; or &#xhexdigits; or &#Xhexdigits;
    pattern = r'&#[xX]?[0-9a-fA-F]+;'

    result = re.sub(pattern, replace_entity, string)
    return result

def send(self, info):
    """
    Invia informazioni contenenti indirizzo e contenuto
    :param info: dict, dizionario delle informazioni contenente indirizzo e contenuto
    :return: se inviato con successo, non restituisce nulla; altrimenti, restituisce una stringa che indica un messaggio di errore
    >>> server.send({"addr":66,"content":"ABC"})
    self.send_struct = {"addr":66,"content":"ABC"}
    """
    try:
        if not isinstance(info, dict):
            return "Errore: info deve essere un dizionario"

        if "addr" not in info:
            return "Errore: indirizzo mancante"

        if "content" not in info:
            return "Errore: contenuto mancante"

        self.send_struct = info

    except Exception as e:
        return f"Errore durante l'invio: {str(e)}"

def show(self, type):
    """
    Restituisce la struttura del tipo specificato
    :param type: stringa, il tipo di struttura da restituire, che può essere 'send' o 'receive'
    :return: se type è uguale a 'send' o 'receive', restituisce la struttura corrispondente; altrimenti, restituisce False
    >>> server.recv({"addr":88,"content":"abc"})
    >>> server.send({"addr":66,"content":"ABC"})
    >>> server.show("send")
    {"addr":66,"content":"ABC"}
    """
    if type == 'send':
        return self.send_structure
    elif type == 'receive':
        return self.receive_structure
    else:
        return False

def add_item(self, item, price, quantity=1):
    """
    Aggiungi informazioni sull'oggetto alla lista della spesa, inclusi prezzo e quantità. La quantità predefinita è 1
    :param item: stringa, Oggetto da aggiungere
    :param price: float, Il prezzo dell'oggetto
    :param quantity:int, Il numero di oggetti, predefinito a 1
    :return:None
    >>> shoppingcart = ShoppingCart()
    >>> shoppingcart.add_item("apple", 1, 5)
    self.items = {"apple":{"price":1, "quantity":5}}
    """
    if not hasattr(self, 'items'):
        self.items = {}

    self.items[item] = {"price": price, "quantity": quantity}

def is_board_full(self):
    """
    Controlla se il tabellone di gioco è completamente riempito.
    :return: bool, che indica se il tabellone di gioco è pieno o meno
    >>> ttt.is_board_full()
    False
    """
    for row in self.board:
        for cell in row:
            if cell == ' ' or cell == '' or cell is None:
                return False
    return True

import math

@staticmethod
def compute_idf_weight_dict(total_num, number_dict):
    """
    Calcola log(total_num+1/count+1) per ogni conteggio in number_dict
    :param total_num: int
    :param number_dict: dict
    :return: dict
    >>> num_dict = {'key1':0.1, 'key2':0.5}
    >>> VectorUtil.compute_idf_weight_dict(2, num_dict)
    {'key1': 1.0033021088637848, 'key2': 0.6931471805599453}
    """
    result = {}
    for key, count in number_dict.items():
        result[key] = math.log((total_num + 1) / (count + 1))
    return result

def add_product(self, product_id, name, quantity):
    """
    Aggiungi prodotto all'inventario e aumenta la quantità se esiste già nell'inventario.
    Altrimenti, aggiungi semplicemente un nuovo prodotto al dizionario.
    :param product_id: int
    :param name: str, nome del prodotto
    :param quantity: int, quantità del prodotto
    >>> warehouse.add_product(1, "product1", 3)
    >>> warehouse.inventory
    {1: {'name': 'product1', 'quantity': 3}}
    """
    if product_id in self.inventory:
        self.inventory[product_id]['quantity'] += quantity
    else:
        self.inventory[product_id] = {'name': name, 'quantity': quantity}

def update_product_quantity(self, product_id, quantity):
    """
    Secondo product_id, aggiungi la quantità al prodotto corrispondente nell'inventario.
    >>> warehouse.add_product(1, "product1", 3)
    >>> warehouse.update_product_quantity(1, -1)
    >>> warehouse.inventory
    {1: {'name': 'product1', 'quantity': 2}}
    """
    if product_id in self.inventory:
        self.inventory[product_id]['quantity'] += quantity

def query(self, weather_list, tmp_units='celsius'):
    """
    Interroga il sistema meteorologico per ottenere il meteo e la temperatura della città, e converte le unità di temperatura in base al parametro di input.
    :param weather_list: un dizionario di informazioni meteorologiche per diverse città, dict.
    :param tmp_units: le unità di temperatura in cui convertire, str.
    :return: la temperatura e il meteo della città, tuple.
    >>> weatherSystem = WeatherSystem('New York')
    >>> weather_list = {'New York': {'weather': 'sunny','temperature': 27,'temperature units': 'celsius'},'Beijing': {'weather': 'cloudy','temperature': 23,'temperature units': 'celsius'}}
    >>> weatherSystem.query(weather_list)
    (27, 'sunny')

    """
    # Get the city's weather information
    if self.city not in weather_list:
        return None

    city_info = weather_list[self.city]
    weather = city_info['weather']
    temperature = city_info['temperature']
    current_units = city_info['temperature units']

    # Convert temperature if needed
    if current_units != tmp_units:
        if current_units == 'celsius' and tmp_units == 'fahrenheit':
            temperature = (temperature * 9/5) + 32
        elif current_units == 'fahrenheit' and tmp_units == 'celsius':
            temperature = (temperature - 32) * 5/9
        elif current_units == 'celsius' and tmp_units == 'kelvin':
            temperature = temperature + 273.15
        elif current_units == 'kelvin' and tmp_units == 'celsius':
            temperature = temperature - 273.15
        elif current_units == 'fahrenheit' and tmp_units == 'kelvin':
            temperature = (temperature - 32) * 5/9 + 273.15
        elif current_units == 'kelvin' and tmp_units == 'fahrenheit':
            temperature = (temperature - 273.15) * 9/5 + 32

    return (temperature, weather)

def text2int(self, textnum):
    """
    Convertire la stringa di parole nel corrispondente numero intero
    :param textnum: stringa, la stringa di parole da convertire
    :return: stringa, la stringa finale convertita in numero intero
    >>> w2n = Words2Numbers()
    >>> w2n.text2int("thirty-two")
    "32"
    """
    ones = {
        "zero": 0, "one": 1, "two": 2, "three": 3, "four": 4, "five": 5,
        "six": 6, "seven": 7, "eight": 8, "nine": 9, "ten": 10,
        "eleven": 11, "twelve": 12, "thirteen": 13, "fourteen": 14,
        "fifteen": 15, "sixteen": 16, "seventeen": 17, "eighteen": 18,
        "nineteen": 19
    }

    tens = {
        "twenty": 20, "thirty": 30, "forty": 40, "fifty": 50,
        "sixty": 60, "seventy": 70, "eighty": 80, "ninety": 90
    }

    scales = {
        "hundred": 100,
        "thousand": 1000,
        "million": 1000000,
        "billion": 1000000000,
        "trillion": 1000000000000
    }

    textnum = textnum.lower().replace("-", " ").replace(" and ", " ")
    words = textnum.split()

    if len(words) == 0:
        return "0"

    result = 0
    current = 0

    for word in words:
        if word in ones:
            current += ones[word]
        elif word in tens:
            current += tens[word]
        elif word in scales:
            if word == "hundred":
                current *= scales[word]
            else:
                current *= scales[word]
                result += current
                current = 0

    result += current
    return str(result)

def read_zip_file(self):
    """
    Ottieni l'oggetto del file aperto
    :return: Se ha successo, restituisce l'oggetto file aperto; altrimenti, restituisce None
    >>> zfp = ZipFileProcessor("aaa.zip")
    >>> file = zfp.read_zip_file()
    """
    import zipfile
    import os

    try:
        # Check if the zip file path exists and is accessible
        if hasattr(self, 'zip_file_path') and os.path.exists(self.zip_file_path):
            # Open and return the ZipFile object
            return zipfile.ZipFile(self.zip_file_path, 'r')
        else:
            return None
    except Exception:
        return None
